import { AES, enc } from 'crypto-js';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { ENCRYPTION_KEY } from './config';

export const encryptData = (data) => {
  return AES.encrypt(JSON.stringify(data), ENCRYPTION_KEY).toString();
};

export const decryptData = (cipherText) => {
  const bytes = AES.decrypt(cipherText, ENCRYPTION_KEY);
  return JSON.parse(bytes.toString(enc.Utf8));
};

export const storeEncryptedData = async (key, data) => {
  try {
    const encryptedData = encryptData(data);
    await AsyncStorage.setItem(key, encryptedData);
  } catch (error) {
    console.error('Error storing encrypted data', error);
  }
};

export const retrieveEncryptedData = async (key) => {
  try {
    const encryptedData = await AsyncStorage.getItem(key);
    if (encryptedData !== null) {
      return decryptData(encryptedData);
    }
    return null;
  } catch (error) {
    console.error('Error retrieving encrypted data', error);
    return null;
  }
};

